import Stripe from 'stripe';
import { db } from '../db/index.js';

const stripe = new Stripe(process.env.STRIPE_SECRET_KEY!);

export async function createSetupIntent(customerId: string): Promise<string> {
  const intent = await stripe.setupIntents.create({
    customer: customerId,
    usage: 'off_session',
  });
  return intent.client_secret!;
}

export async function confirmSetupIntent(intentId: string): Promise<void> {
  const intent = await stripe.setupIntents.retrieve(intentId);
  if (intent.status !== 'succeeded') {
    throw new Error(`SetupIntent ${intentId} did not succeed: ${intent.status}`);
  }
  await db.paymentMethods.upsert({
    customerId: intent.customer as string,
    stripePaymentMethodId: intent.payment_method as string,
    isDefault: true,
  });
}

